final:
module RefModule(
   input                clk ,
   input                rst_n,
   input                up_down,

   output reg [3-1:1-1]     Q  
);
    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) Q <= 3'b0;
        else if(up_down) Q <= Q + 1;
        else Q <= Q - 1;
    end
endmodule
